<?php
namespace Tests\Feature;
use App\Domain\Hunts\Sessions\HuntingSessionService;use App\Domain\Inventory\CharacterInventorySummaryService;use App\Domain\Inventory\InventoryService;use App\Models\Character;use App\Models\HuntingSession;use App\Models\Item;use App\Models\User;use App\Models\Zone;use Database\Seeders\WorldCatalogSeeder;use Illuminate\Foundation\Testing\RefreshDatabase;use Tests\TestCase;
class HuntingSessionInventoryDisplayTest extends TestCase{use RefreshDatabase;protected function setUp():void{parent::setUp();$this->seed(WorldCatalogSeeder::class);}private function character(){return Character::factory()->for(User::factory())->create(['base_attack'=>500]);}private function zone(){return Zone::where('code','grey_oak_forest')->firstOrFail();}
public function test_summary_is_controlled_ordered_and_calculates_slots(){$c=$this->character();$z=Item::create(['code'=>'z_item','name'=>'Zeta','item_type'=>'material','rarity'=>'common','is_stackable'=>true,'max_stack'=>2,'status'=>'active']);$a=Item::create(['code'=>'a_item','name'=>'Alfa','item_type'=>'material','rarity'=>'common','is_stackable'=>false,'max_stack'=>1,'status'=>'active']);app(InventoryService::class)->addItem($c,$z,3);\App\Models\CharacterItem::create(['character_id'=>$c->id,'item_id'=>$a->id,'quantity'=>2,'locked_quantity'=>0]);$snapshot=app(CharacterInventorySummaryService::class)->snapshot($c);$this->assertSame(['Alfa','Zeta'],array_column($snapshot['inventory_items'],'item_name'));$this->assertSame([2,2],array_column($snapshot['inventory_items'],'used_slots'));$this->assertSame(4,$snapshot['inventory_status']['current_used_slots']);foreach($snapshot['inventory_items'] as $row)$this->assertIsArray($row);}
public function test_hunting_show_has_inventory_and_distinct_reward_summaries_but_tick_has_no_items(){$c=$this->character();$service=app(HuntingSessionService::class);$session=HuntingSession::find($service->start($c,$this->zone())->id());$response=$this->actingAs($c->user)->get(route('characters.hunting-sessions.show',[$c,$session]));$response->assertOk()->assertSee('Inventario actual')->assertSee('Recompensas pendientes del personaje')->assertSee('Obtenido en esta sesión')->assertSee('function renderInventoryItems',false)->assertSee('function updateClaimButton',false)->assertDontSee('innerHTML',false);$tick=$service->tick($c,$session)->toArray();$this->assertArrayHasKey('session_pending_rewards_summary',$tick);$this->assertArrayHasKey('character_pending_rewards_summary',$tick);$this->assertArrayNotHasKey('inventory_items',$tick);}
public function test_empty_inventory_snapshot_is_valid(){$snapshot=app(CharacterInventorySummaryService::class)->snapshot($this->character());$this->assertSame([],$snapshot['inventory_items']);$this->assertSame(0,$snapshot['inventory_status']['current_used_slots']);}
}
